def main():
    import sys
    S = list(sys.stdin.readline().strip())
    i = 0
    while i < len(S) - 1:
        if S[i] == 'W' and S[i+1] == 'A':
            S[i] = 'A'
            S[i+1] = 'C'
            i = max(0, i - 1)  # Recheck the previous part of the string
        else:
            i += 1
    print(''.join(S))

if __name__ == "__main__":
    main()
